import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import './Navbar.css';

const NAV_ITEMS = [
  { id: 'classes',     label: 'Classes'       },
  { id: 'upload',      label: 'Upload Papers' },
  { id: 'keys',        label: 'Answer Keys'   },
  { id: 'results',     label: 'Results'       },
  { id: 'analytics',   label: 'Analytics'     },
  { id: 'answersheet', label: 'Answer Sheets' },
];

const BASE_URL = 'http://localhost:8000';

function ChangePasswordModal({ onClose }) {
  const { token }  = useAuth();
  const [cur,  setCur]  = useState('');
  const [next, setNext] = useState('');
  const [msg,  setMsg]  = useState('');
  const [err,  setErr]  = useState('');
  const [busy, setBusy] = useState(false);

  const handleSave = async () => {
    if (!cur || !next) { setErr('Please fill in both fields.'); return; }
    if (next.length < 6) { setErr('New password must be at least 6 characters.'); return; }
    setBusy(true); setErr(''); setMsg('');
    try {
      const res = await fetch(`${BASE_URL}/api/auth/change-password`, {
        method:  'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ current_password: cur, new_password: next }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.detail || 'Failed');
      setMsg('Password changed successfully!');
      setCur(''); setNext('');
    } catch (e) { setErr(e.message); }
    finally { setBusy(false); }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal modal-sm" onClick={e => e.stopPropagation()}>
        <div className="modal-header">
          <h2>Change Password</h2>
          <button className="btn-icon" onClick={onClose}>✕</button>
        </div>
        <div className="modal-body" style={{ gap: 12 }}>
          {err && <div className="alert alert-error"><span>{err}</span></div>}
          {msg && <div className="alert alert-success"><span>{msg}</span></div>}
          <div className="field-group">
            <label className="field-label">Current Password</label>
            <input className="field-input" type="password"
              value={cur} onChange={e => setCur(e.target.value)} />
          </div>
          <div className="field-group">
            <label className="field-label">New Password</label>
            <input className="field-input" type="password"
              placeholder="At least 6 characters"
              value={next} onChange={e => setNext(e.target.value)} />
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" onClick={handleSave} disabled={busy}>
            {busy ? 'Saving...' : 'Save Password'}
          </button>
        </div>
      </div>
    </div>
  );
}

export default function Navbar({ activePage, setActivePage }) {
  const [menuOpen,    setMenuOpen]    = useState(false);
  const [showChgPass, setShowChgPass] = useState(false);
  const { teacherName, logout } = useAuth();

  const handleNav = (id) => {
    setActivePage(id);
    setMenuOpen(false);
  };

  return (
    <header className="navbar">
      <div className="navbar-inner">
        {/* Brand */}
        <button className="navbar-brand" onClick={() => handleNav('classes')}>
          <span className="brand-icon" aria-hidden="true">
            <svg width="22" height="22" viewBox="0 0 22 22" fill="none">
              <rect x="2" y="2" width="18" height="18" rx="4"
                stroke="currentColor" strokeWidth="1.5"/>
              <path d="M6 8h10M6 11h7M6 14h5" stroke="currentColor"
                strokeWidth="1.5" strokeLinecap="round"/>
              <circle cx="17" cy="15" r="3.5" fill="var(--accent)"
                stroke="var(--cream)" strokeWidth="1"/>
              <path d="M15.8 15l.8.8 1.4-1.4" stroke="white"
                strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          </span>
          <span className="brand-name">ExamCheck <em>AI</em></span>
        </button>

        {/* Desktop nav */}
        <nav className="navbar-nav" aria-label="Main navigation">
          {NAV_ITEMS.map(item => (
            <button
              key={item.id}
              className={`nav-link ${activePage === item.id ? 'active' : ''}`}
              onClick={() => handleNav(item.id)}
              aria-current={activePage === item.id ? 'page' : undefined}
            >
              {item.label}
            </button>
          ))}
        </nav>

        {/* Right side */}
        <div className="navbar-right">
          <div className="navbar-badge">
            <span className="status-dot" aria-hidden="true" />
            {teacherName || 'Teacher'}
          </div>
          <button className="btn-chgpass" onClick={() => setShowChgPass(true)} title="Change password">
            <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
              <circle cx="7" cy="5" r="3" stroke="currentColor" strokeWidth="1.3"/>
              <path d="M2 13c0-2.76 2.24-5 5-5s5 2.24 5 5"
                stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/>
            </svg>
            <span className="chgpass-label">Account</span>
          </button>
          <button className="btn-logout" onClick={logout} title="Sign out">
            <svg width="15" height="15" viewBox="0 0 15 15" fill="none">
              <path d="M6 2H3a1 1 0 0 0-1 1v9a1 1 0 0 0 1 1h3"
                stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/>
              <path d="M10 10l3-2.5L10 5M13 7.5H6"
                stroke="currentColor" strokeWidth="1.3"
                strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
            <span className="logout-label">Sign Out</span>
          </button>
          <button className="hamburger" onClick={() => setMenuOpen(o => !o)}
            aria-label="Toggle menu" aria-expanded={menuOpen}>
            <span className={`ham-line ${menuOpen ? 'open' : ''}`} />
            <span className={`ham-line ${menuOpen ? 'open' : ''}`} />
            <span className={`ham-line ${menuOpen ? 'open' : ''}`} />
          </button>
        </div>
      </div>

      {/* Mobile menu */}
      {menuOpen && (
        <div className="mobile-menu">
          {NAV_ITEMS.map(item => (
            <button key={item.id}
              className={`mobile-nav-link ${activePage === item.id ? 'active' : ''}`}
              onClick={() => handleNav(item.id)}>
              {item.label}
            </button>
          ))}
          <button className="mobile-nav-link" onClick={() => { setShowChgPass(true); setMenuOpen(false); }}>
            Account Settings
          </button>
          <button className="mobile-nav-link mobile-logout" onClick={logout}>
            Sign Out
          </button>
        </div>
      )}

      {showChgPass && <ChangePasswordModal onClose={() => setShowChgPass(false)} />}
    </header>
  );
}
